export async function main(_ctx, _input) {
  const buf = new ArrayBuffer(8);
  const dv = new DataView(buf);
  dv.setUint32(0, 0x01020304, true);
  dv.setFloat32(4, 1.5, true);
  const u8 = new Uint8Array(buf);
  const clamped = new Uint8ClampedArray([-5, 300, 127.8]);
  return { ok: true, value: {
    leU32: dv.getUint32(0, true), beU32: dv.getUint32(0, false),
    f32: dv.getFloat32(4, true), bytes: Array.from(u8),
    clamped: Array.from(clamped), int8: new Int8Array([200])[0]
  } };
}
